"""
Task 058 – Round 3 (B2)  – Final
Generate individuals.csv: for each participant, find their best-fit (model, rule)
pair and count how many participants share each pair.

Output: pred_results/individuals.csv
Format: "Model; Rule; Num persons" (semicolon-separated)

Key lessons from round-2 failure:
- Rule modules could not be called via heuristic function-name guessing.
- Instead, we instantiate them as ccobra models (class-based interface).
- We also more carefully parse the model CSV files.
- We use the ccobra syllogistic encoding throughout.
"""

import os
import sys
import importlib.util
from collections import Counter, defaultdict

import pandas as pd
import numpy as np

# ---------------------------------------------------------------------------
# Paths
# ---------------------------------------------------------------------------
BASE_DIR = os.path.dirname(os.path.abspath(__file__))
NVC_DIR  = os.path.join(BASE_DIR, "benchmark", "datasets", "nvc")
INDIV_MODELS_DIR = os.path.join(NVC_DIR, "scripts", "indiv_table", "models")
INDIV_RULES_DIR  = os.path.join(NVC_DIR, "scripts", "indiv_table", "rules")
PRED_RESULTS_DIR = os.path.join(BASE_DIR, "pred_results")
os.makedirs(PRED_RESULTS_DIR, exist_ok=True)

import ccobra
import ccobra.syllogistic as syl

# ---------------------------------------------------------------------------
# Syllogistic encoding helpers
# ---------------------------------------------------------------------------
QUANT_MAP = {"All": "A", "Some": "I", "Some not": "O", "No": "E"}
QUANT_REV = {"A": "All", "I": "Some", "O": "Some not", "E": "No"}

def encode_task(task_str):
    """
    Parse 'Q1;A;B/Q2;C;D' and return (syl_code, enc_task) where:
      syl_code = e.g. 'AI1'
      enc_task = ccobra encoded form [[[q1, t1, t2], [q2, t3, t4]], ...]
    Returns (None, None) on failure.
    """
    try:
        parts = task_str.split("/")
        p1 = [x.strip() for x in parts[0].split(";")]
        p2 = [x.strip() for x in parts[1].split(";")]
        q1 = QUANT_MAP.get(p1[0])
        q2 = QUANT_MAP.get(p2[0])
        if q1 is None or q2 is None:
            return None, None
        t11, t12 = p1[1], p1[2]
        t21, t22 = p2[1], p2[2]
        # Determine figure
        if t12 == t21:
            fig = 1
        elif t11 == t21:
            fig = 2
        elif t12 == t22:
            fig = 3
        elif t11 == t22:
            fig = 4
        else:
            fig = 1  # fallback
        syl_code = q1 + q2 + str(fig)
        enc_task = [[[q1, t11, t12], [q2, t21, t22]], []]
        return syl_code, enc_task
    except Exception:
        return None, None

def encode_response(resp_str, enc_task):
    """
    Parse participant response 'Q;term1;term2' or 'NVC' into ccobra encoding.
    Returns encoded response list or 'NVC'.
    """
    resp_str = resp_str.strip()
    if resp_str == "NVC":
        return "NVC"
    try:
        parts = [x.strip() for x in resp_str.split(";")]
        q = QUANT_MAP.get(parts[0])
        if q is None:
            return resp_str
        t1, t2 = parts[1], parts[2]
        return [q, t1, t2]
    except Exception:
        return resp_str

# ---------------------------------------------------------------------------
# Load participant data
# ---------------------------------------------------------------------------
ragni_path = os.path.join(NVC_DIR, "Ragni2016.csv")
df_raw = pd.read_csv(ragni_path)

# participant_id -> list of (task_str, syl_code, enc_task, enc_response)
participant_data = defaultdict(list)
for _, row in df_raw.iterrows():
    pid = int(row["id"])
    task_str = str(row["task"]).strip()
    resp_str = str(row["response"]).strip()
    syl_code, enc_task = encode_task(task_str)
    enc_resp = encode_response(resp_str, enc_task)
    participant_data[pid].append((task_str, syl_code, enc_task, enc_resp, resp_str))

# ---------------------------------------------------------------------------
# Load model CSV predictions
# Each CSV has predictions per syllogism.
# We detect format dynamically but with smarter heuristics.
# ---------------------------------------------------------------------------
MODEL_NAMES = ["PSYCOP", "Matching", "VerbalModels", "MMT", "Conversion", "PHM", "Atmosphere"]

# All ccobra syllogism codes
ALL_SYL_CODES = list(syl.SYLLOGISMS)  # e.g. ['AA1','AA2','AA3','AA4','AE1',...]

def load_model_csv(model_name):
    """
    Returns dict: {syl_code -> set_of_predicted_responses}
    where responses are quantifier-only codes like 'A','I','O','E','NVC'
    or full encoded strings. We store raw strings from CSV for flexible matching.
    """
    fpath = os.path.join(INDIV_MODELS_DIR, f"{model_name}.csv")
    df_m = pd.read_csv(fpath, header=0)
    cols = list(df_m.columns)
    preds = defaultdict(set)

    # Check if first column values look like syl codes (2 letters + digit)
    first_col_vals = df_m.iloc[:, 0].dropna().astype(str).tolist()
    looks_like_sylcodes_rows = sum(
        1 for v in first_col_vals[:10]
        if len(v) == 3 and v[:2].isalpha() and v[2].isdigit()
    )

    # Check if column names look like syl codes
    syl_cols = [c for c in cols if len(str(c)) == 3 and str(c)[:2].isalpha() and str(c)[2].isdigit()]

    if looks_like_sylcodes_rows >= 3:
        # Format: rows indexed by syl code, prediction(s) in remaining columns
        for _, row in df_m.iterrows():
            sc = str(row.iloc[0]).strip()
            for col in cols[1:]:
                val = str(row[col]).strip()
                if val and val.lower() not in ("nan", "none", ""):
                    preds[sc].add(val)
    elif len(syl_cols) >= 10:
        # Format: columns are syl codes, rows are response labels
        # Value = 1 (or True) means this response is predicted for this syllogism
        resp_col = cols[0]
        for _, row in df_m.iterrows():
            resp_label = str(row[resp_col]).strip()
            for sc in syl_cols:
                try:
                    v = row[sc]
                    if pd.notna(v) and float(v) != 0:
                        preds[sc].add(resp_label)
                except (ValueError, TypeError):
                    if str(row[sc]).strip().lower() not in ("", "nan", "0", "false"):
                        preds[sc].add(resp_label)
    else:
        # Try: single column after first is the prediction
        if len(cols) >= 2:
            for _, row in df_m.iterrows():
                sc = str(row.iloc[0]).strip()
                val = str(row.iloc[1]).strip()
                if val and val.lower() not in ("nan", "none", ""):
                    preds[sc].add(val)

    return dict(preds)

model_preds = {}
for mname in MODEL_NAMES:
    try:
        model_preds[mname] = load_model_csv(mname)
    except Exception as e:
        print(f"Warning: could not load model {mname}: {e}", file=sys.stderr)
        model_preds[mname] = {}

# ---------------------------------------------------------------------------
# Load and instantiate rule modules as ccobra models
# ---------------------------------------------------------------------------
RULE_NAMES = ["negativity", "figural", "emptystart", "particularity", "atmosphere", "partneg"]

def load_rule_module(rname, rules_dir):
    fpath = os.path.join(rules_dir, f"{rname}.py")
    if not os.path.exists(fpath):
        return None
    # Add directories to sys.path for imports
    for d in [rules_dir, os.path.dirname(rules_dir), NVC_DIR]:
        if d not in sys.path:
            sys.path.insert(0, d)
    try:
        spec = importlib.util.spec_from_file_location(f"rule_{rname}", fpath)
        mod = importlib.util.module_from_spec(spec)
        spec.loader.exec_module(mod)
        return mod
    except Exception as e:
        print(f"Warning: could not load rule {rname}: {e}", file=sys.stderr)
        return None

rule_modules = {}
for rname in RULE_NAMES:
    rule_modules[rname] = load_rule_module(rname, INDIV_RULES_DIR)

# ---------------------------------------------------------------------------
# Try to instantiate ccobra-style model from rule module
# ccobra models typically have a class that extends ccobra.CCobraModel
# with methods: pre_train, predict, etc.
# ---------------------------------------------------------------------------
def find_model_class(mod):
    """Find the main model class in a module (subclass of ccobra.CCobraModel or similar)."""
    if mod is None:
        return None
    for attr_name in dir(mod):
        attr = getattr(mod, attr_name)
        try:
            if (isinstance(attr, type) and
                    attr.__module__ == mod.__name__ and
                    hasattr(attr, 'predict')):
                return attr
        except Exception:
            pass
    # Also try any class with predict method regardless of module
    for attr_name in dir(mod):
        attr = getattr(mod, attr_name)
        try:
            if isinstance(attr, type) and hasattr(attr, 'predict') and attr_name not in ('object',):
                return attr
        except Exception:
            pass
    return None

# ---------------------------------------------------------------------------
# Build a ccobra Dataset for pre_train
# ---------------------------------------------------------------------------
def build_ccobra_dataset(participant_data):
    """Build a ccobra.CCobraDataset from participant data for pre_train."""
    try:
        dataset_list = []
        for pid, tasks in participant_data.items():
            for task_str, syl_code, enc_task, enc_resp, resp_str in tasks:
                if enc_task is None:
                    continue
                dataset_list.append({
                    "id": pid,
                    "task": enc_task,
                    "response": enc_resp,
                    "response_str": resp_str,
                    "syl_code": syl_code,
                })
        return dataset_list
    except Exception:
        return []

dataset_list = build_ccobra_dataset(participant_data)

# Instantiate rule models
rule_instances = {}
for rname, mod in rule_modules.items():
    cls = find_model_class(mod)
    if cls is None:
        rule_instances[rname] = None
        continue
    try:
        instance = cls()
        rule_instances[rname] = instance
    except Exception as e:
        print(f"Warning: could not instantiate rule {rname}: {e}", file=sys.stderr)
        rule_instances[rname] = None

# Pre-train rule models with participant data if they support it
# Build ccobra-compatible dataset
try:
    import ccobra
    # Try to create a proper ccobra dataset
    ccobra_items = []
    for entry in dataset_list:
        if entry["enc_task"] is not None if "enc_task" in entry else entry.get("task") is not None:
            try:
                item = ccobra.CCobraItem(entry["task"], "syllogistic", entry["response"], "single-choice", [entry["response"]])
                ccobra_items.append((entry["id"], item))
            except Exception:
                pass
except Exception:
    ccobra_items = []

# Pre-train each rule instance
for rname, instance in rule_instances.items():
    if instance is None:
        continue
    try:
        if hasattr(instance, 'pre_train') and ccobra_items:
            # Build participant-specific training data
            # Just call pre_train with empty or minimal data to initialize
            instance.pre_train([])
    except Exception:
        pass

# ---------------------------------------------------------------------------
# Build rule prediction maps via direct module-level functions or class instances
# Strategy: for each syl_code, get prediction set from each rule
# ---------------------------------------------------------------------------
def get_rule_preds_for_syl(rname, syl_code, enc_task):
    """Get set of predicted responses from a rule for a given syllogism."""
    mod = rule_modules.get(rname)
    instance = rule_instances.get(rname)
    predicted = set()

    # Try instance-based prediction first
    if instance is not None:
        try:
            # ccobra predict interface: predict(item)
            item = ccobra.CCobraItem(enc_task, "syllogistic", None, "single-choice", [])
            result = instance.predict(item)
            if result is not None:
                if isinstance(result, (list, tuple)):
                    for r in result:
                        predicted.add(str(r).strip() if not isinstance(r, list) else ";".join(str(x) for x in r))
                else:
                    predicted.add(str(result).strip())
        except Exception:
            pass

    # Try module-level functions
    if not predicted and mod is not None:
        for fn_name in ("predict", "apply", "rule", "apply_rule", "get_prediction", "get_predictions", "nvc_predict"):
            fn = getattr(mod, fn_name, None)
            if fn is None:
                continue
            for arg in (syl_code, enc_task, (syl_code,), [syl_code]):
                try:
                    result = fn(arg)
                    if result is None:
                        continue
                    if isinstance(result, (list, set, tuple)):
                        for r in result:
                            predicted.add(str(r).strip() if not isinstance(r, list) else ";".join(str(x) for x in r))
                    else:
                        predicted.add(str(result).strip())
                    if predicted:
                        break
                except Exception:
                    continue
            if predicted:
                break

    # Try module-level dict or lookup table
    if not predicted and mod is not None:
        for attr_name in ("PREDICTIONS", "predictions", "PRED", "pred", "TABLE", "table", "NVC_PREDS"):
            attr = getattr(mod, attr_name, None)
            if isinstance(attr, dict) and syl_code in attr:
                val = attr[syl_code]
                if isinstance(val, (list, set, tuple)):
                    predicted.update(str(v) for v in val)
                else:
                    predicted.add(str(val))
                break

    return predicted

# Pre-compute rule prediction maps: {syl_code -> set_of_responses}
rule_pred_maps = {}
# Gather all syl codes we need
all_syl_codes_needed = set()
for tasks in participant_data.values():
    for _, syl_code, _, _, _ in tasks:
        if syl_code:
            all_syl_codes_needed.add(syl_code)

# Also collect enc_tasks per syl_code
syl_to_enc_task = {}
for tasks in participant_data.values():
    for task_str, syl_code, enc_task, _, _ in tasks:
        if syl_code and syl_code not in syl_to_enc_task and enc_task is not None:
            syl_to_enc_task[syl_code] = enc_task

for rname in RULE_NAMES:
    rule_pred_maps[rname] = {}
    for sc in all_syl_codes_needed:
        enc_task = syl_to_enc_task.get(sc)
        if enc_task:
            rule_pred_maps[rname][sc] = get_rule_preds_for_syl(rname, sc, enc_task)

# ---------------------------------------------------------------------------
# Response matching
# We need to compare participant response to model/rule predicted responses.
# Model CSVs may store responses as quantifier codes (A,I,O,E,NVC) or full strings.
# Participant responses are full strings like 'Some;managers;clerks' or 'NVC'.
# We normalize for comparison.
# ---------------------------------------------------------------------------

def normalize_response(resp):
    """Normalize a response to a canonical form for matching."""
    resp = str(resp).strip()
    if resp.upper() == "NVC":
        return "NVC"
    # Try to extract quantifier
    parts = resp.split(";")
    if len(parts) >= 1:
        q = QUANT_MAP.get(parts[0].strip())
        if q:
            # Return both full and quantifier-only
            return resp  # keep full for set lookup
    # Already a code (A, I, O, E)?
    if resp in ("A", "I", "O", "E", "NVC"):
        return resp
    return resp

def response_matches(resp_str, predicted_set):
    """
    Check if participant response resp_str matches any prediction in predicted_set.
    Handles: full strings, quantifier-only codes, direction-agnostic matching.
    """
    if not predicted_set:
        return False
    resp_str = str(resp_str).strip()

    # NVC
    if resp_str.upper() == "NVC":
        return any(str(p).strip().upper() == "NVC" for p in predicted_set)

    # Parse participant response
    resp_parts = [x.strip() for x in resp_str.split(";")]
    resp_q = QUANT_MAP.get(resp_parts[0]) if resp_parts else None  # e.g. 'I'

    for pred in predicted_set:
        pred = str(pred).strip()
        if not pred or pred.lower() in ("nan", "none"):
            continue

        # Direct string match
        if pred.lower() == resp_str.lower():
            return True

        # Quantifier-only code match (e.g., predicted = 'I')
        if resp_q and pred == resp_q:
            return True
        # Code with direction: e.g., 'Iac' or 'Ica'
        if resp_q and len(pred) == 3 and pred[0] == resp_q:
            return True

        # Predicted is full string — compare quantifier
        pred_parts = [x.strip() for x in pred.split(";")]
        if len(pred_parts) >= 1:
            pred_q = QUANT_MAP.get(pred_parts[0])
            if pred_q and resp_q and pred_q == resp_q:
                # Match if quantifier matches (direction-agnostic for some models)
                return True

    return False

# ---------------------------------------------------------------------------
# Compute best-fit model for each participant
# ---------------------------------------------------------------------------
def compute_best_fit(participant_tasks, pred_maps, names):
    """
    For each name in names, count how many tasks match the predictions.
    Return the name with the highest count (ties: first in list wins).
    """
    best_name = None
    best_count = -1
    for name in names:
        pmap = pred_maps.get(name, {})
        count = 0
        for task_str, syl_code, enc_task, enc_resp, resp_str in participant_tasks:
            if syl_code and syl_code in pmap:
                if response_matches(resp_str, pmap[syl_code]):
                    count += 1
        if count > best_count:
            best_count = count
            best_name = name
    return best_name if best_name else names[0]

# ---------------------------------------------------------------------------
# Debug: print some model prediction info
# ---------------------------------------------------------------------------
print("=== Model prediction sample ===", file=sys.stderr)
for mname in MODEL_NAMES:
    pmap = model_preds[mname]
    print(f"  {mname}: {len(pmap)} syllogisms, sample: {dict(list(pmap.items())[:2])}", file=sys.stderr)

print("=== Rule prediction sample ===", file=sys.stderr)
for rname in RULE_NAMES:
    rmap = rule_pred_maps[rname]
    non_empty = {k: v for k, v in rmap.items() if v}
    print(f"  {rname}: {len(rmap)} syllogisms, non-empty: {len(non_empty)}, sample: {dict(list(non_empty.items())[:2])}", file=sys.stderr)

# ---------------------------------------------------------------------------
# Main loop: best-fit per participant
# ---------------------------------------------------------------------------
pair_counter = Counter()

for pid, tasks in participant_data.items():
    best_model = compute_best_fit(tasks, model_preds, MODEL_NAMES)
    best_rule  = compute_best_fit(tasks, rule_pred_maps, RULE_NAMES)
    pair_counter[(best_model, best_rule)] += 1

# ---------------------------------------------------------------------------
# Write output
# ---------------------------------------------------------------------------
rows = []
for (model, rule), count in sorted(pair_counter.items()):
    rows.append({"Model": model, "Rule": rule, "Num persons": count})

out_df = pd.DataFrame(rows, columns=["Model", "Rule", "Num persons"])
out_path = os.path.join(PRED_RESULTS_DIR, "individuals.csv")
out_df.to_csv(out_path, sep=";", index=False)

print(f"Written {len(out_df)} rows to {out_path}")
print(out_df.to_string(index=False))
print(f"\nTotal participants: {sum(pair_counter.values())}")

